import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useApp } from '../context/AppContext';
import { generateDemoSteps, generateDemoWater, generateDemoWeight } from '../utils/helpers';

export default function RegisterPage() {
  const { dispatch } = useApp();
  const navigate = useNavigate();
  const [step, setStep] = useState(1);
  const [form, setForm] = useState({
    name: '', email: '', password: '',
    height: '', weight: '', age: '', gender: 'male',
  });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const nextStep = () => {
    if (!form.name || !form.email || !form.password) { setError('Vui lòng điền đầy đủ'); return; }
    if (form.password.length < 6) { setError('Mật khẩu tối thiểu 6 ký tự'); return; }
    setError('');
    setStep(2);
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!form.height || !form.weight || !form.age) { setError('Vui lòng điền đầy đủ thông tin'); return; }
    setLoading(true);

    setTimeout(() => {
      const users = JSON.parse(localStorage.getItem('health_users') || '[]');
      if (users.find(u => u.email === form.email)) {
        setError('Email đã được sử dụng');
        setLoading(false);
        return;
      }
      users.push({ name: form.name, email: form.email, password: form.password });
      localStorage.setItem('health_users', JSON.stringify(users));

      const profile = {
        name: form.name, email: form.email,
        height: +form.height, weight: +form.weight,
        age: +form.age, gender: form.gender,
      };
      localStorage.setItem(`health_profile_${form.email}`, JSON.stringify(profile));

      // Seed demo history data
      const demoSteps = generateDemoSteps();
      const demoWater = generateDemoWater();
      const demoWeight = generateDemoWeight();
      localStorage.setItem('health_steps', JSON.stringify(demoSteps));
      localStorage.setItem('health_water', JSON.stringify(demoWater));
      localStorage.setItem('health_weight', JSON.stringify(demoWeight));

      dispatch({ type: 'LOGIN', payload: { email: form.email, name: form.name } });
      dispatch({ type: 'SET_PROFILE', payload: profile });
      navigate('/dashboard');
    }, 1000);
  };

  return (
    <div style={styles.page}>
      <div style={styles.bg} />
      <div style={styles.card}>
        <div style={styles.logo}>
          <div style={styles.logoIcon}>♥</div>
          <div>
            <div style={styles.logoName}>VitaTrack</div>
            <div style={styles.logoSub}>Health Monitor</div>
          </div>
        </div>

        {/* Step indicator */}
        <div style={styles.steps}>
          {[1,2].map(s => (
            <React.Fragment key={s}>
              <div style={{ ...styles.stepDot, ...(s <= step ? styles.stepDotActive : {}) }}>
                {s < step ? '✓' : s}
              </div>
              {s < 2 && <div style={{ ...styles.stepLine, ...(s < step ? styles.stepLineActive : {}) }} />}
            </React.Fragment>
          ))}
        </div>

        <h1 style={styles.title}>{step === 1 ? 'Tạo tài khoản' : 'Hồ sơ sức khỏe'}</h1>
        <p style={styles.sub}>{step === 1 ? 'Bắt đầu hành trình chăm sóc sức khỏe.' : 'Để chúng tôi cá nhân hóa cho bạn.'}</p>

        {step === 1 ? (
          <div style={styles.form}>
            <div className="input-group">
              <label className="input-label">Họ và tên</label>
              <input className="input-field" placeholder="Nguyễn Văn A" value={form.name} onChange={e => setForm({ ...form, name: e.target.value })} />
            </div>
            <div className="input-group">
              <label className="input-label">Email</label>
              <input type="email" className="input-field" placeholder="your@email.com" value={form.email} onChange={e => setForm({ ...form, email: e.target.value })} />
            </div>
            <div className="input-group">
              <label className="input-label">Mật khẩu</label>
              <input type="password" className="input-field" placeholder="Tối thiểu 6 ký tự" value={form.password} onChange={e => setForm({ ...form, password: e.target.value })} />
            </div>
            {error && <div style={styles.error}>{error}</div>}
            <button className="btn btn-primary" style={{ width: '100%', marginTop: 8 }} onClick={nextStep}>
              Tiếp theo →
            </button>
          </div>
        ) : (
          <form onSubmit={handleSubmit} style={styles.form}>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 14 }}>
              <div className="input-group">
                <label className="input-label">Chiều cao (cm)</label>
                <input type="number" className="input-field" placeholder="170" value={form.height} onChange={e => setForm({ ...form, height: e.target.value })} />
              </div>
              <div className="input-group">
                <label className="input-label">Cân nặng (kg)</label>
                <input type="number" className="input-field" placeholder="65" value={form.weight} onChange={e => setForm({ ...form, weight: e.target.value })} />
              </div>
            </div>
            <div className="input-group">
              <label className="input-label">Tuổi</label>
              <input type="number" className="input-field" placeholder="25" value={form.age} onChange={e => setForm({ ...form, age: e.target.value })} />
            </div>
            <div className="input-group">
              <label className="input-label">Giới tính</label>
              <div style={styles.genderGroup}>
                {[{ v: 'male', l: '♂ Nam' }, { v: 'female', l: '♀ Nữ' }].map(g => (
                  <button
                    key={g.v} type="button"
                    onClick={() => setForm({ ...form, gender: g.v })}
                    style={{ ...styles.genderBtn, ...(form.gender === g.v ? styles.genderBtnActive : {}) }}
                  >
                    {g.l}
                  </button>
                ))}
              </div>
            </div>
            {error && <div style={styles.error}>{error}</div>}
            <div style={{ display: 'flex', gap: 10 }}>
              <button type="button" className="btn btn-ghost" style={{ flex: 1 }} onClick={() => setStep(1)}>← Quay lại</button>
              <button type="submit" className="btn btn-primary" style={{ flex: 2 }} disabled={loading}>
                {loading ? 'Đang tạo...' : '🎉 Hoàn tất'}
              </button>
            </div>
          </form>
        )}

        <p style={styles.switchText}>
          Đã có tài khoản?{' '}
          <Link to="/login" style={styles.link}>Đăng nhập</Link>
        </p>
      </div>
    </div>
  );
}

const styles = {
  page: { minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 20, position: 'relative' },
  bg: { position: 'fixed', inset: 0, background: 'radial-gradient(ellipse at 80% 50%, rgba(168,85,247,0.08) 0%, transparent 60%), radial-gradient(ellipse at 20% 80%, rgba(0,229,160,0.06) 0%, transparent 60%)', pointerEvents: 'none' },
  card: { background: 'rgba(22,29,46,0.9)', backdropFilter: 'blur(20px)', border: '1px solid rgba(255,255,255,0.08)', borderRadius: 24, padding: '40px 36px', width: '100%', maxWidth: 440, position: 'relative', zIndex: 1, animation: 'fadeInUp 0.5s ease', boxShadow: '0 24px 80px rgba(0,0,0,0.5)' },
  logo: { display: 'flex', alignItems: 'center', gap: 12, marginBottom: 28 },
  logoIcon: { width: 44, height: 44, background: 'linear-gradient(135deg, #00e5a0, #00a87a)', borderRadius: 12, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 22, color: '#000', fontWeight: 800, boxShadow: '0 4px 20px rgba(0,229,160,0.3)' },
  logoName: { fontFamily: 'var(--font-display)', fontWeight: 800, fontSize: 18, color: '#f0f4ff' },
  logoSub: { fontSize: 11, color: '#4a5568', textTransform: 'uppercase', letterSpacing: '1px' },
  steps: { display: 'flex', alignItems: 'center', gap: 0, marginBottom: 24 },
  stepDot: { width: 32, height: 32, borderRadius: '50%', background: 'rgba(255,255,255,0.06)', border: '1px solid rgba(255,255,255,0.1)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontFamily: 'var(--font-display)', fontWeight: 700, fontSize: 13, color: '#4a5568', flexShrink: 0 },
  stepDotActive: { background: 'rgba(0,229,160,0.15)', border: '1px solid #00e5a0', color: '#00e5a0' },
  stepLine: { flex: 1, height: 2, background: 'rgba(255,255,255,0.06)', margin: '0 8px' },
  stepLineActive: { background: '#00e5a0' },
  title: { fontFamily: 'var(--font-display)', fontSize: 26, fontWeight: 800, color: '#f0f4ff', marginBottom: 6 },
  sub: { fontSize: 14, color: '#8892aa', marginBottom: 28 },
  form: { display: 'flex', flexDirection: 'column', gap: 16 },
  error: { background: 'rgba(255,79,139,0.1)', border: '1px solid rgba(255,79,139,0.3)', borderRadius: 10, padding: '10px 14px', fontSize: 13, color: '#ff4f8b' },
  genderGroup: { display: 'flex', gap: 10 },
  genderBtn: { flex: 1, padding: '10px', borderRadius: 10, background: 'var(--bg-secondary)', border: '1px solid rgba(255,255,255,0.06)', color: '#8892aa', cursor: 'pointer', fontFamily: 'var(--font-display)', fontWeight: 600, fontSize: 13, transition: 'all 0.2s ease' },
  genderBtnActive: { background: 'rgba(0,229,160,0.1)', border: '1px solid #00e5a0', color: '#00e5a0' },
  switchText: { textAlign: 'center', marginTop: 24, fontSize: 14, color: '#8892aa' },
  link: { color: '#00e5a0', textDecoration: 'none', fontWeight: 600 },
};
